class Solution:
    def findMissingAndRepeatedValues(self, grid: List[List[int]]) -> List[int]:
        n = len(grid)
        freq = [0] * (n * n + 1)

        for row in grid:
            for x in row:
                freq[x] += 1

        repeated = -1
        missing = -1
        for x in range(1, n * n + 1):
            if freq[x] == 2:
                repeated = x
            elif freq[x] == 0:
                missing = x

        return [repeated, missing]
