from typing import List

class Solution:
    def findMissingAndRepeatedValues(self, grid: List[List[int]]) -> List[int]:
        n = len(grid)
        seen = set()
        repeated = None
        missing = None

        # Since values are exactly in [1, n^2], we can mark seen values.
        for row in grid:
            for x in row:
                if x in seen:
                    repeated = x
                else:
                    seen.add(x)

        # Find the missing number: present in [1..n^2] but not in seen
        target = n * n
        for x in range(1, target + 1):
            if x not in seen:
                missing = x
                break

        return [repeated, missing]
```

