from typing import List

class Solution:
    def findMissingAndRepeatedValues(self, grid: List[List[int]]) -> List[int]:
        n = len(grid)
        seen = set()
        repeated = -1
        total_sum = 0

        for row in grid:
            for x in row:
                total_sum += x
                if x in seen:
                    repeated = x
                else:
                    seen.add(x)

        # Expected sum from 1..n^2
        expected_sum = n * n * (n * n + 1) // 2
        missing = expected_sum - total_sum + repeated  # derive from sums

        return [repeated, missing]
